INSERT OR REPLACE INTO quality_profiles (name, description, upgrades_allowed, minimum_custom_format_score, upgrade_until_score, upgrade_score_increment) VALUES ('Alex_C.T - 1080p-2160p Plex Series', 'Primary Sonarr profile for modern series. It prefers feature-rich 1080p first, then compact 2160p as a fallback, then weaker 1080p releases. Series only gain credit for the language, subtitle, codec, HDR, audio, release-fix, and source features they actually have, so richer releases rise naturally without negative guards.', 1, 0, 16000, 125);
