INSERT OR REPLACE INTO quality_profiles (name, description, upgrades_allowed, minimum_custom_format_score, upgrade_until_score, upgrade_score_increment) VALUES ('Alex_C.T - 4K Plex Series', 'Manual 4K Sonarr profile for shows that deserve the 2160p path. Profilarr ladder displays top-to-bottom as Bluray-2160p then WEBDL-2160p, while richer HDR/Dolby Vision, codec, language, subtitle, and audio features simply add more credit. There are no negative guards or minimum-score gates in the default profile, so the best feature set wins naturally.', 1, 0, 16000, 125);
